129	njs_int_t
130	njs_builtin_objects_create(njs_vm_t *vm)
131	{
132	    njs_int_t                  ret, index;
133	    njs_uint_t                 i;
134	    njs_object_t               *object, *string_object;
135	    njs_function_t             *constructor;
136	    njs_vm_shared_t            *shared;
137	    njs_regexp_pattern_t       *pattern;
138	    njs_object_prototype_t     *prototype;
139	    const njs_object_init_t    *obj, **p;
140	
141	    shared = njs_mp_zalloc(vm->mem_pool, sizeof(njs_vm_shared_t));
142	    if (njs_slow_path(shared == NULL)) {
143	        return NJS_ERROR;
144	    }
145	
146	    vm->shared = shared;
147	
148	    njs_flathsh_init(&shared->values_hash);
149	
150	    vm->atom_id_generator = njs_atom_hash_init(vm);
151	    if (njs_slow_path(vm->atom_id_generator == 0xffffffff)) {
152	        return NJS_ERROR;
153	    }
154	
155	    pattern = njs_regexp_pattern_create(vm, (u_char *) "(?:)",
156	                                        njs_length("(?:)"), 0);
157	    if (njs_slow_path(pattern == NULL)) {
158	        return NJS_ERROR;
159	    }
160	
161	    shared->empty_regexp_pattern = pattern;
162	
163	    ret = njs_object_hash_init(vm, &shared->array_instance_hash,
164	                               &njs_array_instance_init);
165	    if (njs_slow_path(ret != NJS_OK)) {
166	        return NJS_ERROR;
167	    }
168	
169	    ret = njs_object_hash_init(vm, &shared->string_instance_hash,
170	                               &njs_string_instance_init);
171	    if (njs_slow_path(ret != NJS_OK)) {
172	        return NJS_ERROR;
173	    }
174	
175	    ret = njs_object_hash_init(vm, &shared->function_instance_hash,
176	                               &njs_function_instance_init);
177	    if (njs_slow_path(ret != NJS_OK)) {
178	        return NJS_ERROR;
179	    }
180	
181	    ret = njs_object_hash_init(vm, &shared->async_function_instance_hash,
182	                               &njs_async_function_instance_init);
183	    if (njs_slow_path(ret != NJS_OK)) {
184	        return NJS_ERROR;
185	    }
186	
187	    ret = njs_object_hash_init(vm, &shared->arrow_instance_hash,
188	                               &njs_arrow_instance_init);
189	    if (njs_slow_path(ret != NJS_OK)) {
190	        return NJS_ERROR;
191	    }
192	
193	    ret = njs_object_hash_init(vm, &shared->arguments_object_instance_hash,
194	                               &njs_arguments_object_instance_init);
195	    if (njs_slow_path(ret != NJS_OK)) {
196	        return NJS_ERROR;
197	    }
198	
199	    ret = njs_object_hash_init(vm, &shared->regexp_instance_hash,
200	                               &njs_regexp_instance_init);
201	    if (njs_slow_path(ret != NJS_OK)) {
202	        return NJS_ERROR;
203	    }
204	
205	    object = shared->objects;
206	
207	    for (p = njs_object_init; *p != NULL; p++) {
208	        obj = *p;
209	
210	        ret = njs_object_hash_init(vm, &object->shared_hash, obj);
211	        if (njs_slow_path(ret != NJS_OK)) {
212	            return NJS_ERROR;
213	        }
214	
215	        object->type = NJS_OBJECT;
216	        object->shared = 1;
217	        object->extensible = 1;
218	
219	        object++;
220	    }
221	
222	    ret = njs_env_hash_init(vm, &shared->env_hash, environ);
223	    if (njs_slow_path(ret != NJS_OK)) {
224	        return NJS_ERROR;
225	    }
226	
227	    for (i = NJS_OBJ_TYPE_OBJECT; i < NJS_OBJ_TYPE_MAX; i++) {
228	        index = njs_vm_ctor_push(vm);
229	        if (njs_slow_path(index < 0)) {
230	            return NJS_ERROR;
231	        }
232	
233	        njs_assert_msg((njs_uint_t) index == i,
234	                       "ctor index should match object type");
235	
236	        prototype = njs_shared_prototype(shared, i);
237	        *prototype = njs_object_type_init[i]->prototype_value;
238	
239	        if (njs_object_type_init[i] == &njs_boolean_type_init) {
240	            prototype->object_value.value = njs_value(NJS_BOOLEAN, 0, 0.0);
241	
242	        } else if (njs_object_type_init[i] == &njs_number_type_init) {
243	            prototype->object_value.value = njs_value(NJS_NUMBER, 0, 0.0);
244	
245	        } else if (njs_object_type_init[i] == &njs_string_type_init) {
246	            njs_set_empty_string(vm, &prototype->object_value.value);
247	        }
248	
249	        ret = njs_object_hash_init(vm, &prototype->object.shared_hash,
250	                                   njs_object_type_init[i]->prototype_props);
251	        if (njs_slow_path(ret != NJS_OK)) {
252	            return NJS_ERROR;
253	        }
254	
255	        prototype->object.extensible = 1;
256	    }
257	
258	    prototype = njs_shared_prototype(shared, NJS_OBJ_TYPE_REGEXP);
259	    prototype->regexp.pattern = shared->empty_regexp_pattern;
260	
261	    for (i = NJS_OBJ_TYPE_OBJECT; i < NJS_OBJ_TYPE_MAX; i++) {
262	        constructor = njs_shared_ctor(shared, i);
263	
264	        if (njs_object_type_init[i]->constructor_props == NULL) {
265	            njs_memzero(constructor, sizeof(njs_function_t));
266	            continue;
267	        }
268	
269	        *constructor = njs_object_type_init[i]->constructor;
270	        constructor->object.shared = 0;
271	
272	        ret = njs_object_hash_init(vm, &constructor->object.shared_hash,
273	                                   njs_object_type_init[i]->constructor_props);
274	        if (njs_slow_path(ret != NJS_OK)) {
275	            return NJS_ERROR;
276	        }
277	    }
278	
279	    shared->global_slots.prop_handler = njs_global_this_prop_handler;
280	    shared->global_slots.writable = 1;
281	    shared->global_slots.configurable = 1;
282	    shared->global_slots.enumerable = 1;
283	
284	    shared->objects[0].slots = &shared->global_slots;
285	
286	    vm->global_object = shared->objects[0];
287	    vm->global_object.shared = 0;
288	
289	    string_object = &shared->string_object;
290	    njs_flathsh_init(&string_object->hash);
291	    string_object->shared_hash = shared->string_instance_hash;
292	    string_object->type = NJS_OBJECT_VALUE;
293	    string_object->shared = 1;
294	    string_object->extensible = 0;
295	
296	    njs_flathsh_init(&shared->modules_hash);
297	
298	    return NJS_OK;
299	}
