302	static njs_int_t
303	njs_ext_dump(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
304	    njs_index_t unused, njs_value_t *retval)
305	{
306	    uint32_t     n;
307	    njs_int_t    ret;
308	    njs_str_t    str;
309	    njs_value_t  *value, *indent;
310	
311	    value = njs_arg(args, nargs, 1);
312	    indent = njs_arg(args, nargs, 2);
313	
314	    ret = njs_value_to_uint32(vm, indent, &n);
315	    if (njs_slow_path(ret != NJS_OK)) {
316	        return ret;
317	    }
318	
319	    n = njs_min(n, 5);
320	
321	    if (njs_vm_value_dump(vm, &str, value, 1, n) != NJS_OK) {
322	        return NJS_ERROR;
323	    }
324	
325	    return njs_string_create(vm, retval, str.start, str.length);
326	}
