329	static njs_int_t
330	njs_ext_on(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
331	    njs_index_t unused, njs_value_t *retval)
332	{
333	    njs_str_t    type;
334	    njs_uint_t   i, n;
335	    njs_value_t  *value;
336	
337	    static const struct {
338	        njs_str_t   name;
339	        njs_uint_t  id;
340	    } hooks[] = {
341	        {
342	            njs_str("exit"),
343	            NJS_HOOK_EXIT
344	        },
345	    };
346	
347	    value = njs_arg(args, nargs, 1);
348	
349	    if (njs_slow_path(!njs_is_string(value))) {
350	        njs_type_error(vm, "hook type is not a string");
351	        return NJS_ERROR;
352	    }
353	
354	    njs_string_get(vm, value, &type);
355	
356	    i = 0;
357	    n = sizeof(hooks) / sizeof(hooks[0]);
358	
359	    while (i < n) {
360	        if (njs_strstr_eq(&type, &hooks[i].name)) {
361	            break;
362	        }
363	
364	        i++;
365	    }
366	
367	    if (i == n) {
368	        njs_type_error(vm, "unknown hook type \"%V\"", &type);
369	        return NJS_ERROR;
370	    }
371	
372	    value = njs_arg(args, nargs, 2);
373	
374	    if (njs_slow_path(!njs_is_function(value) && !njs_is_null(value))) {
375	        njs_type_error(vm, "callback is not a function or null");
376	        return NJS_ERROR;
377	    }
378	
379	    vm->hooks[i] = njs_is_function(value) ? njs_function(value) : NULL;
380	
381	    return NJS_OK;
382	}
