385	static njs_int_t
386	njs_ext_memory_stats(njs_vm_t *vm, njs_object_prop_t *prop, uint32_t unused,
387	    njs_value_t *unused2, njs_value_t *unused3, njs_value_t *retval)
388	{
389	    njs_int_t      ret;
390	    njs_value_t    object, value;
391	    njs_object_t   *stat;
392	    njs_mp_stat_t  mp_stat;
393	
394	    stat = njs_object_alloc(vm);
395	    if (njs_slow_path(stat == NULL)) {
396	        return NJS_ERROR;
397	    }
398	
399	    njs_set_object(&object, stat);
400	
401	    njs_mp_stat(vm->mem_pool, &mp_stat);
402	
403	    njs_set_number(&value, mp_stat.size);
404	
405	    ret = njs_value_property_set(vm, &object, NJS_ATOM_STRING_size, &value);
406	    if (njs_slow_path(ret != NJS_OK)) {
407	        return NJS_ERROR;
408	    }
409	
410	    njs_set_number(&value, mp_stat.nblocks);
411	
412	    ret = njs_value_property_set(vm, &object, NJS_ATOM_STRING_nblocks, &value);
413	    if (njs_slow_path(ret != NJS_OK)) {
414	        return NJS_ERROR;
415	    }
416	
417	    njs_set_number(&value, mp_stat.cluster_size);
418	
419	    ret = njs_value_property_set(vm, &object, NJS_ATOM_STRING_cluster_size,
420	                                 &value);
421	    if (njs_slow_path(ret != NJS_OK)) {
422	        return NJS_ERROR;
423	    }
424	
425	    njs_set_number(&value, mp_stat.page_size);
426	
427	    ret = njs_value_property_set(vm, &object, NJS_ATOM_STRING_page_size, &value);
428	    if (njs_slow_path(ret != NJS_OK)) {
429	        return NJS_ERROR;
430	    }
431	
432	    njs_set_object(retval, stat);
433	
434	    return NJS_OK;
435	}
