440	static njs_int_t
441	njs_global_this_prop_handler(njs_vm_t *vm, njs_object_prop_t *prop,
442	    uint32_t atom_id, njs_value_t *global, njs_value_t *setval,
443	    njs_value_t *retval)
444	{
445	    njs_value_t          *value;
446	    njs_variable_t       *var;
447	    njs_rbtree_node_t    *rb_node;
448	    njs_variable_node_t  *node, var_node;
449	
450	    if (retval == NULL) {
451	        return NJS_DECLINED;
452	    }
453	
454	    var_node.key = atom_id;
455	
456	    if (njs_slow_path(vm->global_scope == NULL)) {
457	        return NJS_DECLINED;
458	    }
459	
460	    rb_node = njs_rbtree_find(&vm->global_scope->variables, &var_node.node);
461	    if (rb_node == NULL) {
462	        return NJS_DECLINED;
463	    }
464	
465	    node = (njs_variable_node_t *) rb_node;
466	
467	    var = node->variable;
468	
469	    if (var->type == NJS_VARIABLE_LET || var->type == NJS_VARIABLE_CONST) {
470	        return NJS_DECLINED;
471	    }
472	
473	    value = njs_scope_valid_value(vm, var->index);
474	
475	    if (setval != NULL) {
476	        njs_value_assign(value, setval);
477	    }
478	
479	    njs_value_assign(retval, value);
480	
481	    return NJS_OK;
482	}
