485	static njs_int_t
486	njs_global_this_object(njs_vm_t *vm, njs_object_prop_t *self, uint32_t atom_id,
487	    njs_value_t *global, njs_value_t *setval, njs_value_t *retval)
488	{
489	    njs_int_t            ret;
490	    njs_object_prop_t    *prop;
491	    njs_flathsh_query_t  fhq;
492	
493	    if (retval == NULL) {
494	        return NJS_DECLINED;
495	    }
496	
497	    njs_value_assign(retval, global);
498	
499	    if (njs_slow_path(setval != NULL)) {
500	        njs_value_assign(retval, setval);
501	    }
502	
503	    fhq.key_hash = atom_id;
504	    fhq.replace = 1;
505	    fhq.pool = vm->mem_pool;
506	    fhq.proto = &njs_object_hash_proto;
507	
508	    ret = njs_flathsh_unique_insert(njs_object_hash(global), &fhq);
509	    if (njs_slow_path(ret != NJS_OK)) {
510	        njs_internal_error(vm, "flathsh insert/replace failed");
511	        return NJS_ERROR;
512	    }
513	
514	    prop = fhq.value;
515	
516	    prop->type = NJS_PROPERTY;
517	    prop->enumerable = self->enumerable;
518	    prop->configurable = 1;
519	    prop->writable = 1;
520	    prop->u.value = *retval;
521	
522	    return NJS_OK;
523	}
