526	static njs_int_t
527	njs_top_level_object(njs_vm_t *vm, njs_object_prop_t *self, uint32_t atom_id,
528	    njs_value_t *global, njs_value_t *setval, njs_value_t *retval)
529	{
530	    njs_int_t            ret;
531	    njs_object_t         *object;
532	    njs_object_prop_t    *prop;
533	    njs_flathsh_query_t  fhq;
534	
535	    if (njs_slow_path(setval != NULL)) {
536	        njs_value_assign(retval, setval);
537	
538	    } else {
539	        if (njs_slow_path(retval == NULL)) {
540	            return NJS_DECLINED;
541	        }
542	
543	        njs_set_object(retval, &vm->shared->objects[njs_prop_magic16(self)]);
544	
545	        object = njs_object_value_copy(vm, retval);
546	        if (njs_slow_path(object == NULL)) {
547	            return NJS_ERROR;
548	        }
549	
550	        object->__proto__ = njs_vm_proto(vm, NJS_OBJ_TYPE_OBJECT);
551	    }
552	
553	    fhq.key_hash = atom_id;
554	    fhq.replace = 1;
555	    fhq.pool = vm->mem_pool;
556	    fhq.proto = &njs_object_hash_proto;
557	
558	    ret = njs_flathsh_unique_insert(njs_object_hash(global), &fhq);
559	    if (njs_slow_path(ret != NJS_OK)) {
560	        njs_internal_error(vm, "flathsh insert/replace failed");
561	        return NJS_ERROR;
562	    }
563	
564	    prop = fhq.value;
565	
566	    prop->type = NJS_PROPERTY;
567	    prop->enumerable = self->enumerable;
568	    prop->configurable = 1;
569	    prop->writable = 1;
570	    prop->u.value = *retval;
571	
572	    return NJS_OK;
573	}
