576	static njs_int_t
577	njs_top_level_constructor(njs_vm_t *vm, njs_object_prop_t *self,
578	    uint32_t atom_id, njs_value_t *global, njs_value_t *setval,
579	    njs_value_t *retval)
580	{
581	    njs_int_t            ret;
582	    njs_function_t       *ctor;
583	    njs_object_prop_t    *prop;
584	    njs_flathsh_query_t  fhq;
585	
586	    if (njs_slow_path(setval != NULL)) {
587	        njs_value_assign(retval, setval);
588	
589	    } else {
590	        if (njs_slow_path(retval == NULL)) {
591	            return NJS_DECLINED;
592	        }
593	
594	        ctor = &njs_vm_ctor(vm, njs_prop_magic16(self));
595	
596	        njs_set_function(retval, ctor);
597	
598	        return NJS_OK;
599	    }
600	
601	    fhq.key_hash = atom_id;
602	    fhq.replace = 1;
603	    fhq.pool = vm->mem_pool;
604	    fhq.proto = &njs_object_hash_proto;
605	
606	    ret = njs_flathsh_unique_insert(njs_object_hash(global), &fhq);
607	    if (njs_slow_path(ret != NJS_OK)) {
