864	static njs_int_t
865	njs_process_object_argv(njs_vm_t *vm, njs_object_prop_t *pr, uint32_t unused,
866	    njs_value_t *process, njs_value_t *unused2, njs_value_t *retval)
867	{
868	    char                 **arg;
869	    njs_int_t            ret;
870	    njs_uint_t           i;
871	    njs_array_t          *argv;
872	    njs_object_prop_t    *prop;
873	    njs_flathsh_query_t  fhq;
874	
875	    argv = njs_array_alloc(vm, 1, vm->options.argc, 0);
876	    if (njs_slow_path(argv == NULL)) {
877	        return NJS_ERROR;
878	    }
879	
880	    i = 0;
881	
882	    for (arg = vm->options.argv; i < vm->options.argc; arg++) {
883	        ret = njs_string_create(vm, &argv->start[i++], (u_char *) *arg,
884	                                njs_strlen(*arg));
885	        if (njs_slow_path(ret != NJS_OK)) {
886	            return NJS_ERROR;
887	        }
888	    }
889	
890	    fhq.key_hash = NJS_ATOM_STRING_argv;
891	    fhq.replace = 1;
892	    fhq.pool = vm->mem_pool;
893	    fhq.proto = &njs_object_hash_proto;
894	
895	    ret = njs_flathsh_unique_insert(njs_object_hash(process), &fhq);
896	    if (njs_slow_path(ret != NJS_OK)) {
897	        njs_internal_error(vm, "flathsh insert failed");
898	        return NJS_ERROR;
899	    }
900	
901	    prop = fhq.value;
902	
903	    prop->type = NJS_PROPERTY;
904	    prop->enumerable = 1;
905	    prop->configurable = 1;
906	    prop->writable = 1;
907	
908	    njs_set_array(njs_prop_value(prop), argv);
909	
910	    njs_value_assign(retval, njs_prop_value(prop));
911	    return NJS_OK;
912	
913	}
