916	static njs_int_t
917	njs_env_hash_init(njs_vm_t *vm, njs_flathsh_t *hash, char **environment)
918	{
919	    char                 **ep;
920	    u_char               *dst;
921	    ssize_t              length;
922	    uint32_t             cp;
923	    njs_int_t            ret;
924	    njs_value_t          prop_name;
925	    const u_char         *val, *entry, *s, *end;
926	    njs_object_prop_t    *prop;
927	    njs_string_prop_t    string;
928	    njs_flathsh_query_t  fhq;
929	
930	    fhq.replace = 0;
931	    fhq.pool = vm->mem_pool;
932	    fhq.proto = &njs_object_hash_proto;
933	
934	    ep = environment;
935	
936	    while (*ep != NULL) {
937	
938	        entry = (u_char *) *ep++;
939	
940	        val = njs_strchr(entry, '=');
941	        if (njs_slow_path(val == NULL)) {
942	            continue;
943	        }
944	
945	        ret = njs_string_create(vm, &prop_name, entry, val - entry);
946	        if (njs_slow_path(ret != NJS_OK)) {
947	            return NJS_ERROR;
948	        }
949	
950	        (void) njs_string_prop(vm, &string, &prop_name);
951	
952	        length = string.length;
953	        s = string.start;
954	        end = s + string.size;
955	        dst = (u_char *) s;
956	
957	        while (length != 0) {
958	            cp = njs_utf8_upper_case(&s, end);
959	            dst = njs_utf8_encode(dst, cp);
960	            length--;
961	        }
962	
963	        val++;
964	
965	        ret = njs_atom_atomize_key(vm, &prop_name);
966	        if (ret != NJS_OK) {
967	            return ret;
968	        }
969	
970	        fhq.key_hash = prop_name.atom_id;
971	
972	        ret = njs_flathsh_unique_insert(hash, &fhq);
973	        if (njs_slow_path(ret != NJS_OK)) {
974	            if (ret == NJS_ERROR) {
975	                njs_internal_error(vm, "flathsh insert failed");
976	                return NJS_ERROR;
977	            }
978	
979	            /* ret == NJS_DECLINED: entry already exists */
980	
981	            /*
982	             * Always using the first element among the duplicates
983	             * and ignoring the rest.
984	             */
985	            continue;
986	        }
987	
988	        prop = fhq.value;
989	
990	        prop->type = NJS_PROPERTY;
991	        prop->enumerable = 1;
992	        prop->configurable = 1;
993	        prop->writable = 1;
994	
995	        ret = njs_string_create(vm, njs_prop_value(prop), val, njs_strlen(val));
996	        if (njs_slow_path(ret != NJS_OK)) {
997	            return NJS_ERROR;
998	        }
999	    }
1000	
1001	    return NJS_OK;
1002	}
