1068	static njs_int_t
1069	njs_ext_process_kill(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1070	    njs_index_t magic, njs_value_t *retval)
1071	{
1072	    int                       signal;
1073	    njs_str_t                 str;
1074	    njs_uint_t                pid;
1075	    njs_value_t               *arg;
1076	    const njs_signal_entry_t  *s;
1077	
1078	    arg = njs_arg(args, nargs, 1);
1079	    if (!njs_value_is_number(arg)) {
1080	        njs_vm_type_error(vm, "\"pid\" is not a number");
1081	        return NJS_ERROR;
1082	    }
1083	
1084	    pid = njs_value_number(arg);
1085	    signal = SIGTERM;
1086	
1087	    arg = njs_arg(args, nargs, 2);
1088	    if (njs_value_is_number(arg)) {
1089	        signal = njs_value_number(arg);
1090	
1091	    } else if (njs_value_is_string(arg)) {
1092	        njs_string_get(vm, arg, &str);
1093	
1094	        if (str.length < 3 || memcmp(str.start, "SIG", 3) != 0) {
1095	            njs_vm_type_error(vm, "\"signal\" unknown value: \"%V\"", &str);
1096	            return NJS_ERROR;
1097	        }
1098	
1099	        str.start += 3;
1100	        str.length -= 3;
1101	
1102	        for (s = &njs_signals_table[0]; s->name.length != 0; s++) {
1103	            if (njs_strstr_eq(&str, &s->name)) {
1104	                signal = s->value;
1105	                break;
1106	            }
1107	        }
1108	
1109	        if (s->name.length == 0) {
1110	            njs_vm_type_error(vm, "\"signal\" unknown value");
1111	            return NJS_ERROR;
1112	        }
1113	
1114	    } else if (!njs_value_is_undefined(arg)) {
1115	        njs_vm_type_error(vm, "\"signal\" invalid type");
1116	        return NJS_ERROR;
1117	    }
1118	
1119	    if (kill(pid, signal) < 0) {
1120	        njs_vm_error(vm, "kill failed with (%d:%s)", errno, strerror(errno));
1121	        return NJS_ERROR;
1122	    }
1123	
1124	    njs_set_boolean(retval, 1);
1125	    return NJS_OK;
1126	}
